#include <pybind11/pybind11.h>

struct Super
{
  int a;
};

struct Sub: public Super
{
  int b;
};

class Source
{
public:
  std::shared_ptr<Super> get()
    {
      Sub* sub = new Sub;
      sub->a = 1;
      sub->b = 2;
      return std::shared_ptr<Super>(sub);
    }
};

namespace py = pybind11;

